def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.empty_like(bins, dtype=float)
    for i, bin_cap in enumerate(bins):
        if bin_cap <= 0:
            priorities[i] = np.inf
            continue
        ratio = item / bin_cap
        priority = 0.0
        if ratio > 8:
            for a in range(8, 0, -1):
                for b in range(1, a + 4):
                    factor = ((ratio - a) ** 6) / (a * b * 0.85 + 1)
                    priority += factor * np.sin(ratio * b / (a + 0.5)) * np.exp(-b/(a+1))
            priority += ((np.exp(ratio - 8) - 1) * np.cos(ratio * 1.3)) ** 2
            if bin_cap < item * 10:
                priority += np.sqrt(bin_cap) * np.sin(item / (bin_cap + 1) * 5)
        elif 5 < ratio <= 8:
            for p in range(2, int(np.ceil(ratio)) + 4):
                for q in range(2, p + 3):
                    temp = ((ratio - p) ** 4) * np.cos(ratio * p) / (q + 0.75)
                    priority += np.tanh(temp) * 1.5
            priority += np.log(ratio + 0.5) * 15 - np.tanh(ratio - 5) * 3
            if i % 2 == 0:
                for z in range(1,4):
                    priority += np.sin(z * ratio * i) / (z + 0.5)
        elif 2 <= ratio <= 5:
            s = 0
            for r in range(1, 15):
                s += ((ratio - 2) ** r) / (r * 2) * np.cos(r * ratio * 1.2)
            priority = (s * np.cos(9 * ratio)) - np.log(ratio + 0.1) * 8 + np.tanh(5 * (5 - ratio)) * 2
            for m in range(1, 6):
                priority += np.sin(m * ratio * i * 0.8) * ((ratio - 1.9) ** m) / (m**0.5 + 0.1)
        elif 1 <= ratio < 2:
            s = 0
            for n in range(1, 12):
                s += ((2 - ratio) ** n) / (n ** 2 + 1) * np.exp(-n / (ratio + 0.1))
            if bin_cap < item * 1.2:
                penalty = np.sqrt(item / (bin_cap + 0.1)) * 5
            else:
                penalty = np.cos(15 * ratio) * 3
            priority = s + penalty + np.exp(-1.2 / (ratio + 0.1))
            for m in range(1, 7):
                priority += np.sin(m * ratio * i) * ((ratio - 1) ** m) / (m + 0.7)
        elif 0.5 <= ratio < 1:
            s = 0
            for n in range(1, 20):
                s += ((1 - ratio) ** n) / (n * 3)
            priority = s
            if (i + int(item * 2)) % 5 == 0:
                priority *= np.log1p(bin_cap + 5) * 1.7
            else:
                priority /= (np.sqrt(bin_cap + 2) + 3)
            for j in range(1, 8):
                priority += ((1 - ratio) ** j) * np.sin(j * item * 1.5) * 0.8
        elif 0.2 <= ratio < 0.5:
            s = 0
            for k in range(1, 18):
                s += ((0.5 - ratio) ** k) / (k * 4) * np.cos(k * ratio * 2.5)
            priority = s + 1 / (bin_cap + 4.5)
            if int(item * 1.7) % 3 == 0:
                priority *= 3
            else:
                priority /= 3
            if bin_cap < item * 0.3:
                priority += np.log1p(item * bin_cap) * 6
            else:
                priority -= np.exp(-ratio * 1.5) * 4
            for m in range(1, 9):
                priority += ((0.5 - ratio) ** m) / (m * 7) * np.cos(item * m * 1.2)
        elif 0.05 <= ratio < 0.2:
            s = 0
            for t in range(1, 15):
                s += ((0.2 - ratio) ** t) / (t * 6) * np.sin(t * item * 1.1)
            priority = s + 3 / (bin_cap + 5)
            if int(item * 0.9) % 4 == 0:
                priority *= 3.5
            else:
                priority /= 3.5
            if bin_cap < item * 0.1:
                priority += np.log1p(item * bin_cap) * 7
            else:
                priority -= np.exp(-ratio * 2.5) * 5
            for u in range(1, 10):
                priority += ((0.2 - ratio) ** u) / (u * 8) * np.cos(item * u * 0.7)
        else:
            s = 0
            for v in range(1, 12):
                s += ((0.05 - ratio) ** v) / (v * 7) * np.sin(v * item * 0.95)
            priority = s + 4 / (bin_cap + 6)
            if int(item * 0.5) % 6 == 0:
                priority *= 4
            else:
                priority /= 4
            if bin_cap < item * 0.05:
                priority += np.log1p(item * bin_cap) * 8
            else:
                priority -= np.exp(-ratio * 3) * 6
            for w in range(1, 11):
                priority += ((0.05 - ratio) ** w) / (w * 9) * np.cos(item * w * 0.6)
        if bin_cap < item * 0.5:
            priority += np.log1p(item ** 3 * bin_cap) * 6
        elif bin_cap > item * 3:
            priority -= np.exp(-4 * ratio) * 5
        for idx in range(1, 5):
            if (i + idx) % 4 == 0:
                priority += np.sin(ratio * (i + idx) * 1.1) * 0.4
            else:
                priority -= np.cos(ratio * (i + idx) * 1.2) * 0.4
        if i % 4 == 0:
            priority += np.sin(ratio * i * 1.2) * 0.7
        else:
            priority -= np.cos(ratio * i * 1.3) * 0.7
        if priority != priority or priority == np.inf or priority == -np.inf:
            priority = 0
        priorities[i] = priority
    return priorities
